div.p:
Architectural equivalence between high-performance ECS and distributed Event Stores.
| {
near: top-center
}

ecs: "ECS Domain: Command Buffer (game_loop.rs)" {
direction: down
style.stroke-width: 2

pre.code:
frame_n: "Frame Execution Boundary (T = 16.6ms)" {
  style.fill: "#E8F5E9"

  systems: "Parallel System Execution" {
    style.fill: "#C8E6C9"
    sys1: "MovementSystem(Query<Pos, Vel>)"
    sys2: "AISystem(Query<Behavior>)"
    sys3: "CombatSystem(Query<Health, Attack>)"
    sys1 -> sys2 -> sys3: "dependency"
  }

  cmd_buf: "Deferred Command Queue (Vec<Command>)" {
    shape: queue
    style.fill: "#81C784"
    c1: "Spawn{id: 42, type: 'Orc'}"
    c2: "AddComp{e: 42, Pos(0,0)}"
    c3: "Destroy{e: 15}"
    c4: "AddComp{e: 7, Buff(Fire)}"
  }
  systems -> cmd_buf: "push_command()"
}

flush: "Sync Point: flush(world)" {
  style.fill: "#FFECB3"
  style.stroke: "#FFA000"

  flush_code: {
    shape: code
    width: 350
    label: |rust
      for cmd in buffer.drain(..) {
        match cmd {
          Spawn{id, ..} => world.spawn(id),
          Destroy{e} => world.despawn(e),
          AddComp{e, c} => world.insert(e, c),
        }
      }
